      "span_text": "وَأَحَلَّ اللَّهُ الْبَيْعَ وَحَرَّمَ الرِّبَا",
      "citation_type": "Aya"
    },
    {
      "span_start": 489,
      "span_end": 543,
      "span_text": "رِجَالٌ لَا تُلْهِيهِمْ تِجَارَةٌ وَلَا بَيْعٌ عَنْ ذِكْرِ اللَّهِ",
      "citation_type": "Aya"
    },
    {
      "span_start": 686,
      "span_end": 790,
      "span_text": "هَلْ أَدُلُّكُمْ عَلَى تِجَارَةٍ تُنْجِيكُمْ مِنْ عَذَابٍ أَلِيمٍ * تُؤْمِنُونَ بِاللَّهِ وَرَسُولِهِ وَتُجَاهِدُونَ فِي سَبِيلِ اللَّهِ بِأَمْوَالِكُمْ وَأَنْفُسِكُمْ ذَلِكُمْ خَيْرٌ لَكُمْ إِنْ كُنْتُمْ تَعْلَمُونَ",
      "citation_type": "Aya"
    },
    {
      "span_start": 913,
      "span_end": 955,
      "span_text": "أفضل الكسب عمل الرجل بيده وكل بيع مبرور",
      "citation_type": "Hadeeth"
    },
    {
      "span_start": 1210,
      "span_end": 1252,
      "span_text": "وَأَحَلَّ اللهُ الْبَيْعَ وَحَرَّمَ الرِّبَا",
      "citation_type": "Aya"
    },
    {
      "span_start": 1260,
      "span_end": 1330,
      "span_text": "لاَ تَأْكُلُواْ أَمْوَالَكُمْ بَيْنَكُمْ بِالْبَاطِلِ إِلاَّ أَن تَكُونَ تِجَارَةً عَن تَرَاضٍ مِّنكُمْ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1400,
      "span_end": 1445,
      "span_text": "بِبَيْعِكُمُ الَّذِي بَايَعْتُمْ بِهِ وَذَلِكَ هُوَ الْفَوْزُ الْعَظِيمُ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1450,
      "span_end": 1504,
      "span_text": "رِجَالٌ لَا تُلْهِيهِمْ تِجَارَةٌ وَلَا بَيْعٌ عَنْ ذِكْرِ اللَّهِ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1510,
      "span_end": 1550,
      "span_text": "وَإِذَا رَأَوْا تِجَارَةً أَوْ لَهْوًا انْفَضُّوا إِلَيْهَا",
      "citation_type": "Aya"
    },
    {
      "span_start": 1555,
      "span_end": 1615,
      "span_text": "هَلْ أَدُلُّكُمْ عَلَى تِجَارَةٍ تُنْجِيكُمْ مِنْ عَذَابٍ أَلِيمٍ، تُؤْمِنُونَ بِاللَّه",
      "citation_type": "Aya"
    },
    {
      "span_start": 1620,
      "span_end": 1650,
      "span_text": "وأحل الله البيع وحرم الربا",
      "citation_type": "Aya"
    },
    {
      "span_start": 1655,
      "span_end": 1690,
      "span_text": "ليس عليكم جناح أن تبتغوا فضلا من ربكم",
      "citation_type": "Aya"
    },
    {
      "span_start": 1695,
      "span_end": 1737,
      "span_text": "أفضل الكسب عمل الرجل بيده وكل بيع مبرور",
      "citation_type": "Hadeeth"
    },
    {
      "span_start": 1740,
      "span_end": 1810,
      "span_text": "ثلاث فيهنّ البركة: البيع إلى أجل، والمقارنة، وخلط البُرّ بالشعير للبيت لا للبيع",
      "citation_type": "Hadeeth"
    }
  ]
}
